SELECT user_id FROM game_rewards
WHERE user_id NOT IN (
    SELECT user_id FROM user_sessions WHERE session_end_date < session_start_date
);

SELECT user_id, COUNT(DISTINCT action_name) AS number_of_unique_actions
FROM user_actions
GROUP BY user_id;

SELECT COUNT(*)
FROM game_updates
WHERE app_id = (SELECT app_id FROM applications WHERE app_name = 'game-02');

SELECT DISTINCT app_name 
FROM user_actions 
WHERE user_id = (SELECT user_id FROM users WHERE username = 'user-01');

SELECT AVG(julianday(session_end_date) - julianday(session_start_date)) AS average_session_length
FROM user_sessions
WHERE app_id = 0;

SELECT app_id, COUNT(DISTINCT user_id) AS unique_reward_users
FROM game_rewards
GROUP BY app_id;
